var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"서둘러 장비를 점검해라!","JPN":"急いで装備を確認しろ！","ENG":"Check your gear, and move it!","TWN":"快去檢查裝備！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"크라켄은 순식간에 너희 몸뚱이를 낚아채 으스러뜨릴 거다!","JPN":"あっという間にクラーケンに捕まって全身を潰されるぞ！","ENG":"Kraken will snatch you up and crush you before you can blink!","TWN":"克拉肯要是揮起觸手，一瞬間就能捏碎你們！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"어설프게 싸울 거면 얌전히 대포알이나 장전해!","JPN":"中途半端に戦うぐらいなら、大人しく砲弾でも装填してろ！","ENG":"If you plan to fight half-heartedly, then sit quiet and load the cannons!","TWN":"要是戰鬥時只想敷衍，那就乖乖去裝填砲彈！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"선원들은 언제 모은 거야?","JPN":"あの船員たち、どうやって集めてきたの？","ENG":"When did you gather this crew?","TWN":"你什麼時候弄來這些船員的？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이런 상황에 침착하게 대응하는 놈들을 찾는 게 쉬운 일은 아니었을 텐데.","JPN":"こんな状況でも冷静に対応できるやつらを探すのは簡単じゃないはずだけど。","ENG":"Finding people who can stay calm in this situation couldn't have been easy.","TWN":"很難找到能在這種情況還保持冷靜的人吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"보물사냥꾼 잭이라는 해적에게서 빌려왔단다.","JPN":"トレジャーハンター・ジャックっていう海賊に貸してもらったのよ。","ENG":"I borrowed them from a pirate called Treasure Hunter Jack.","TWN":"我跟寶藏獵人傑克借來的。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"지난 검은 범람 때 챙긴 보물들로 꽤 벌었다고 들었거든.","JPN":"前回の黒い氾濫で手に入れた宝でかなり儲けたって聞いてね。","ENG":"I heard he made quite a fortune off the treasures from the last Black Flood.","TWN":"聽說他靠上次黑色洪災時撿到的寶物賺了不少。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"관리국한테 뒤를 잡히기 싫으면 나에게 협력하라고 했지.","JPN":"管理局に尻尾を捕まれたくなかったら協力しなさいって言ったの。","ENG":"I told him if he didn't want the Administration sniffing around, he'd best cooperate with me.","TWN":"我只跟他說如果不想被管理局盯上，就乖乖配合我。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그, 그렇구나…….","JPN":"へ、へえ……","ENG":"R-right... I see...","TWN":"原、原來如此……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"크라켄과 싸워보는 건 처음이겠구나.","JPN":"クラーケンと戦うのは初めてよね。","ENG":"This must be your first time facing Kraken.","TWN":"這是妳第一次面對克拉肯吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"두렵지는 않니?","JPN":"怖くはない？","ENG":"Aren't you afraid?","TWN":"不害怕嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리는 저것보다 멀쩡했던 크라켄을 상대로도 이겨냈다며.","JPN":"エイバリーは本調子のクラーケンを相手にして勝ったんだろ。","ENG":"Avery beat Kraken when it was in better shape than that.","TWN":"聽說艾維利戰勝了更完整的克拉肯。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나도 대해적이 되기 위해선 크라켄을 쓰러뜨려야 해.","JPN":"あたしも大海賊になるならクラーケンを倒さなきゃならないんだ。","ENG":"If I want to become a great pirate, I have to defeat Kraken too.","TWN":"如果我想成為大海盜，就必須打倒它。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"두려워할 틈이 없다고.","JPN":"怖がってる暇なんかないよ。","ENG":"I don't have time to be afraid.","TWN":"我根本沒空害怕。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"두려워할 틈이 없다라…….","JPN":"怖がってる暇なんかない、か……","ENG":"Don't have time to be afraid...","TWN":"沒空害怕啊……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIRATE_NPC_FAST_FAST","text":{"KOREA":"선장님! 말씀하신 대로 마하 섬 아래쪽에 거대한 물체가 탐지되었습니다!","JPN":"船長！　おっしゃった通り、マッハ島の下に巨大な物体が探知されました！","ENG":"Captain! Just as you said, a massive object has been detected beneath Macha Island!","TWN":"船長！跟您說的一樣，在瑪查島下方偵測到巨大的物體！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PIRATE_NPC_FAST_FAST","text":{"KOREA":"명령만 내려주십쇼!","JPN":"今すぐご命令を！","ENG":"Just say the word!","TWN":"只要您下令！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"녀석은 지금까지 우리가 만나왔던 괴물 중에서도 궤를 달리하는 존재다.","JPN":"やつは今まで遭遇してきた化け物の中でも桁外れの存在だ。","ENG":"That thing is unlike any monster we've ever faced.","TWN":"那傢伙跟我們之前遇到的怪物根本不是同一個層級。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"어쩌면… 우리 모두 죽음을 각오해야 할지도 몰라.","JPN":"もしかしたら……全員が死を覚悟しなければならないかもしれない。","ENG":"We might... all have to accept death.","TWN":"說不定……大家都得做好赴死的覺悟。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"……두렵지는 않나?","JPN":"……怖くはないか？","ENG":"...Aren't you afraid?","TWN":"……妳不害怕嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"선장, 우리는 두려워할 틈이 없어.","JPN":"船長、私たちに怖がってる暇なんかないよ。","ENG":"Captain, we don't have time to be afraid.","TWN":"船長，我們沒有害怕的時間。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"내일이라는 씨앗의 싹을 틔울 수만 있다면, 난 기꺼이 내 목숨을 거름으로 삼을 거야.","JPN":"明日という種を芽吹かせられるなら、この命が糧になったって構わないんだ。","ENG":"If we can sprout even the tiniest seed of tomorrow, I'll gladly let my life be the soil for it!","TWN":"只要能讓明天這顆種子萌芽，我願意把自己的性命化作養分。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"보니…….","JPN":"ボニー……","ENG":"Bonny...","TWN":"寶妮……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"나도 마찬가지란다, 에이버리.","JPN":"私も同じよ、エイバリー。","ENG":"The same goes for me, Avery.","TWN":"我也是啊，艾維利。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"앞으로 고향을 지켜나갈 아이들이 과거가 아닌, 미래를 꿈꿀 수 있게 된다면…….","JPN":"これから故郷を守っていく子どもたちが、過去じゃなく、未来を夢見ることができるなら……","ENG":"If the children who'll inherit our home can dream of tomorrow instead of clinging to the past...","TWN":"只要能讓守護家鄉的孩子們不再只能活在過去，而能懷抱未來……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"나는 기꺼이 검을 들고 돌격할 거란다.","JPN":"私はよろこんで剣を取り、飛び込むわ。","ENG":"I'll gladly raise my sword and charge.","TWN":"我也願意提起劍衝鋒陷陣。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"리드…….","JPN":"リード……","ENG":"Read...","TWN":"里德……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIRATE_NPC_NULL_ALL","text":{"KOREA":"저희도 마찬가지입니다!","JPN":"俺たちもです！","ENG":"Us too, Captain!","TWN":"我們也一樣。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}}]`);export{e as default};